import boto3
import sys

def create_sns_subscription(topic_arn, endpoint, protocol='https'):
    sns_client = boto3.client('sns')
    
    response = sns_client.subscribe(
        TopicArn=topic_arn,
        Protocol=protocol,
        Endpoint=endpoint
    )
    
    return response

def main():
    sns_client = boto3.client('sns')
    
    print("SNS Subscription Manager")
    print("=" * 50)
    
    topic_arn = input("Enter SNS Topic ARN: ").strip()
    
    if not topic_arn:
        print("Error: Topic ARN is required")
        sys.exit(1)
    
    while True:
        print("\n" + "=" * 50)
        print("Add New Subscription")
        print("=" * 50)
        
        endpoint = input("Enter endpoint URL (or 'quit' to exit): ").strip()
        
        if endpoint.lower() == 'quit':
            print("Exiting...")
            break
        
        protocol = input("Enter protocol (default: https): ").strip() or 'https'
        
        try:
            response = create_sns_subscription(topic_arn, endpoint, protocol)
            
            subscription_arn = response.get('SubscriptionArn', 'N/A')
            print(f"\nSubscription created successfully!")
            print(f"Subscription ARN: {subscription_arn}")
            
        except Exception as e:
            print(f"\nError creating subscription: {str(e)}")
        
        continue_choice = input("\nAdd another subscription? (y/n): ").strip().lower()
        if continue_choice != 'y':
            print("Exiting...")
            break

if __name__ == "__main__":
    main()